{
  "tool": "search_emails",
  "args": {
    "query": "hiking",
    "sender": null
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "You are given the content of one or more emails about a hiking trip with Mark. Extract the following information and output it as a JSON object with keys 'location', 'start_time', 'email'. The 'location' should be the place where the hike will take place. The 'start_time' should be the start date and time of the hike in the format YYYY-MM-DD HH:MM (24-hour clock). The 'email' should be Mark's email address. Email content:\n<tool_result_0/>"
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "From the following JSON, extract the value of the 'location' field. Output only the location string.\n<tool_result_1/>"
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "From the following JSON, extract the value of the 'start_time' field. Output only the start_time string in format YYYY-MM-DD HH:MM.\n<tool_result_1/>"
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "From the following JSON, extract the value of the 'email' field. Output only the email address.\n<tool_result_1/>"
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "Given the start time '<tool_result_3/>' (format YYYY-MM-DD HH:MM), compute the end time that is 5 hours later. Output the end time in the same format."
  }
}
{
  "tool": "create_calendar_event",
  "args": {
    "title": "Hiking Trip with Mark",
    "description": "Hiking trip as discussed with Mark.",
    "location": "<tool_result_2/>",
    "start_time": "<tool_result_3/>",
    "end_time": "<tool_result_5/>",
    "participants": ["<tool_result_4/>"]
  }
}
